// // DFCT0012181 - remove the synchronous option from this method.
// 2.8.3HF   | 2023-09-25 | raj | DFCT0012181 - DIA - Improve Template Creation Response and Avoid thread locking
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// STRY0065506 - added  fields added to the Template for parity
	// TODO - RAJ - You are here thinking about how to take input on theh Template Instance
	// if input comes into the template instance from the launch form or from the run API, pass that to the top task instead of the process template information.
	// Also, question is... if Top Template Task changes, do we update the Template object?
	// if the Template information updates, do we update the Top Task Template to keep in sync?
	// based on that, the Template Instance needs to... check if data entered on the Instance, if not, then use the latest settings.

	// RAJ - STRY 0011909 - modify process template
	// All fields commented were removed from the Process Instance

	gs.debug("Discover Tasker : Business Rule: Tasker Template Instance Copy Start");

	// DFCT0012181 - remove the synchronous option from this method.
	current.u_status = 'queued';

	//current.category = current.routing_template_ref.category;
	//current.classification = current.routing_template_ref.classification;

	// STRY0084305 - many fields updated in template run forms.  Only set if not set from form.
	if(current.discover_template_name + '' == '')
		current.discover_template_name = current.routing_template_ref.template_name;

	//current.estimated_duration = current.routing_template_ref.expected_duration;
	//current.primary_assignee = current.routing_template_ref.primary_assignee;
	//current.primary_office = current.routing_template_ref.primary_office;

	// STRY0084305 - many fields updated in template run forms.  Only set if not set from form.
	if(current.short_description + '' == '')
		current.short_description = current.routing_template_ref.short_description;

	//current.sub_category = current.routing_template_ref.sub_category;

	// RAJ 2018-02-20 - STRY0010804 - copy the Tasking Authority from the Process Definition to the Process Instance on creation.
	//current.tasking_authority = current.routing_template_ref.tasking_authority;
	// description Authority Does not exist on the Template Definition

	// STRY0084305 - many fields updated in template run forms.  Only set if not set from form.
	if(current.description + '' == '')
		current.description = current.routing_template_ref.description;

})(current, previous);
